SELECT "Credit Memo" AS DocType, [Purch_ Cr_ Memo Line].Type, [Purch_ Cr_ Memo Hdr_].No_, [Purch_ Cr_ Memo Hdr_].[VAT Registration No_], [Purch_ Cr_ Memo Hdr_].[Pay-to Name], [Purch_ Cr_ Memo Hdr_].[Pay-to Country_Region Code], Item.[Country_Region of Origin Code], Item.[Tariff No_], -Val([item.Gross Weight])*Val([no_ of pairs]) AS PesoLordo, -Val([no_ of pairs]) AS Unita, Item.Description, -Val([Amount]) AS ImportoNetto, -(Val([Amount])+Val([inv_ discount amount])+Val([Line discount amount])) AS ImportoLordo, Item.[Trademark Code] AS Marchio, Vendor.Name AS Fornitore, [Purch_ Cr_ Memo Hdr_].[Posting Date] AS DataRegistrazione, IIf([Purch_ Cr_ Memo Line.Gen_ Bus_ Posting Group]="NAZIONALE","ITALIA","ESTERO") AS Paese, [Purch_ Cr_ Memo Hdr_].[Currency Code] AS Valuta
FROM ((Item LEFT JOIN Vendor ON Item.[Vendor No_] = Vendor.No_) INNER JOIN [Purch_ Cr_ Memo Line] ON ([Purch_ Cr_ Memo Line].No_ = Item.No_) AND (Item.No_ = [Purch_ Cr_ Memo Line].No_)) INNER JOIN [Purch_ Cr_ Memo Hdr_] ON [Purch_ Cr_ Memo Line].[Document No_] = [Purch_ Cr_ Memo Hdr_].No_
WHERE ((([Purch_ Cr_ Memo Line].Type)=19 Or ([Purch_ Cr_ Memo Line].Type)=20) AND (([Purch_ Cr_ Memo Hdr_].[Posting Date]) Between [forms]![principale]![datainiziale] And [forms]![principale]![datafinale]) AND ((Item.[advertising material])=0));

